const startMs = $('Start Timer').first().json.startMs;
const checks = [];
let allPassed = true;

try {
  const r = $('Check User Service').first().json;
  const ok = !!(r?.status === 'ok' || r?.status === 'healthy' || r?.uptime);
  if (!ok) allPassed = false;
  checks.push({ name: 'user-service', ok, detail: r?.status ?? JSON.stringify(r).slice(0, 100) });
} catch(e) {
  allPassed = false;
  checks.push({ name: 'user-service', ok: false, detail: e.message });
}

try {
  const r = $('Check PT Listing').first().json;
  const payload = r?.body ?? r;
  const arr = Array.isArray(payload)
    ? payload
    : (Array.isArray(payload?.data) ? payload.data : (Array.isArray(payload?.pts) ? payload.pts : null));
  const unauthorized = payload?.code === 'UNAUTHORIZED'
    || payload?.message === 'No token provided'
    || payload?.error?.code === 'UNAUTHORIZED'
    || payload?.error?.message === 'No token provided'
    || r?.statusCode === 401
    || r?.status === 401;
  const ok = arr !== null || unauthorized;
  if (!ok) allPassed = false;

  let detail = payload?.error ?? 'unexpected shape';
  if (arr !== null) detail = `${arr.length} PT(s) listed`;
  if (unauthorized) detail = 'endpoint reachable (auth required)';

  checks.push({ name: 'pt-listing', ok, detail });
} catch(e) {
  allPassed = false;
  checks.push({ name: 'pt-listing', ok: false, detail: e.message });
}

const durationMs = Date.now() - startMs;
return [{ json: {
  passed: allPassed,
  step: 'PT Review',
  statusCode: allPassed ? 200 : 503,
  details: checks.map(c => `${c.name}: ${c.ok ? 'OK' : 'FAIL'}`).join(' | '),
  durationMs,
  checks
} }];
